#include <vector>
#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_jacobi_1d(int tsteps,
		      int n,
		      std::vector<double>& A,
		      std::vector<double>& B) {
    // Avoid repeated look‑ups of vector::data()
    double *a = A.data();
    double *b = B.data();
    const double coeff = 0.33333;      // 1.0/3.0

    for (int t = 0; t < tsteps; ++t) {
        /* First update: B from A */
        #pragma omp parallel for schedule(static)
        for (int i = 1; i < n - 1; ++i) {
            b[i] = coeff * (a[i-1] + a[i] + a[i+1]);
        }

        /* Second update: A from B */
        #pragma omp parallel for schedule(static)
        for (int i = 1; i < n - 1; ++i) {
            a[i] = coeff * (b[i-1] + b[i] + b[i+1]);
        }
    }
}
