void kernel_atax(int m, int n,
                 std::vector<std::vector<double>>& A,
                 std::vector<double>& x,
                 std::vector<double>& y,
                 std::vector<double>& tmp) {
    // Initialise y to zero
    #pragma omp parallel for schedule(static)
    for (int j = 0; j < n; ++j) {
        y[j] = 0.0;
    }

    // Compute tmp[i] = A[i]*x
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < m; ++i) {
        double sum = 0.0;
        double const* Ai = A[i].data();
        for (int j = 0; j < n; ++j) {
            sum += Ai[j] * x[j];
        }
        tmp[i] = sum;
    }

    // Update y[j] += A[i][j] * tmp[i]
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < m; ++i) {
        double const* Ai = A[i].data();
        double yi = tmp[i];
        for (int j = 0; j < n; ++j) {
            #pragma omp atomic
            y[j] += Ai[j] * yi;
        }
    }
}
