void kernel_floyd_warshall(int n, std::vector<std::vector<int>>& path) {
    //  Outer k‑loop must be sequential because it introduces
    //  data dependencies on path[i][k] and path[k][j].
    for (int k = 0; k < n; ++k) {
        // pre‑fetch row k for fast access
        int* row_k = path[k].data();

        // Parallelise the two inner loops over i and j.
        // We use collapse(2) to split work among the 8 threads.
        #pragma omp parallel for collapse(2) schedule(static)
        for (int i = 0; i < n; ++i) {
            int* row_i   = path[i].data();
            int  dik     = row_i[k];           // reuse for all j
            for (int j = 0; j < n; ++j) {
                int sum = dik + row_k[j];
                if (sum < row_i[j])
                    row_i[j] = sum;
            }
        }
    }
}
```
This implementation retains the exact behaviour while:
* Using contiguous row pointers for cache efficiency.
* Caching `path[i][k]` once per `i` instead of recomputing it for every `j`.
* Parallelising the `i`‑`j` loops with OpenMP `collapse(2)` to fully utilize the 8 threads.

