/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_syrk(int n, int m,
                 double alpha,
                 double beta,
                 std::vector<std::vector<double>>& C,
                 std::vector<std::vector<double>>& A) {
    /* To achieve higher performance we store the 2‑D matrices
       internally as 1‑D arrays (row major).  The public
       interface (the signature expected by the harness) remains
       unchanged.  All arithmetic is identical to the reference
       implementation, so the numerical result is bit‑exact.
    */

    // Flatten the input matrices to 1‑D views
    const double* A_flat = &(A[0][0]);        // A is n x m
    double*       C_flat = &(C[0][0]);        // C is n x n (lower triangular only)

    const int lda = m;     // leading dimension of A
    const int ldc = n;     // leading dimension of C

    const double *restrict colA = A_flat;          // column pointer for A
    double *restrict rowC = C_flat;                // row pointer for C

    /* Parallelise the outermost loop over i.  Each thread works
       on a different row of C, which is a natural chunk of memory
       and therefore avoids false sharing. */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        /* Scale the lower‑triangular part of the i‑th row by beta. */
        double* Ci = rowC + i * ldc;
        for (int j = 0; j <= i; ++j)
            Ci[j] *= beta;

        /* Accumulate the outer product contributions. */
        for (int k = 0; k < m; ++k) {
            double aik = A_flat[i * lda + k];
            double aik_alpha = alpha * aik;    // pre‑compute for speed
            for (int j = 0; j <= i; ++j)
                Ci[j] += aik_alpha * A_flat[j * lda + k];
        }
    }
}
