/*  Optimised version of kernel_gesummv
 *  - Uses a single outer OpenMP parallel loop
 *  - Eliminates redundant memory accesses by accumulating
 *    the inner loop results in local temporaries
 *  - Applies SIMD hint for inner loop vectorisation
 *  - Keeps the exact observable behaviour of the original
 */
#include <vector>
#include <omp.h>

void kernel_gesummv(int n,
                    double alpha,
                    double beta,
                    std::vector<std::vector<double>>& A,
                    std::vector<std::vector<double>>& B,
                    std::vector<double>& tmp,
                    std::vector<double>& x,
                    std::vector<double>& y)
{
    /* Parallelise over the outer dimension using static chunking
     * to keep rows balanced.  The vector indexes are used as-is
     * because the original code guarantees row‑major layout.    */
#pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double acc0 = 0.0;   // accumulator for A[i][*] * x[*]
        double acc1 = 0.0;   // accumulator for B[i][*] * x[*]

        /*  Move inner iterations into a single SIMD‑hints loop.
         *  Data is accessed in a naturally vectorised pattern, so
         *  the compiler can emit efficient SSE/AVX instructions.   */
#pragma omp simd
        for (int j = 0; j < n; ++j) {
            acc0 += A[i][j] * x[j];
            acc1 += B[i][j] * x[j];
        }

        tmp[i] = acc0;
        y[i]   = alpha * acc0 + beta * acc1;
    }
}
