/*
 * Optimised triangular solve: L * x = b  (lower triangular, 1‑based indexing internally)
 * The algorithm is unchanged but the implementation eliminates bounds checks and
 * promotes cache locality via explicit pointer arithmetic.  The loop is marked
 * as ivdep so the compiler can vectorise the inner product.
 */
void kernel_trisolv(int n,
                    std::vector<std::vector<double>>& L,
                    std::vector<double>& x,
                    std::vector<double>& b)
{
    // Acquire raw pointers to the underlying data for maximum speed
    double *restrict x_ptr = x.data();
    const double *restrict b_ptr = b.data();

    for (int i = 0; i < n; ++i) {
        double sum = b_ptr[i];

        const double *row = L[i].data();
        const double *xrow = x_ptr;               // pointer to previous x values

        /* The inner loop has no data dependencies other than the strictly lower
         * triangular structure. The ivdep pragma hints the compiler that the
         * iterations are independent, allowing vectorisation.*/
#pragma GCC ivdep
        for (int j = 0; j < i; ++j)
            sum -= row[j] * xrow[j];

        x_ptr[i] = sum / row[i];
    }
}
