/* Optimised 2‑matrix multiplication kernel.
 * Maintains identical semantic behaviour to the reference code.
 */
void kernel_2mm(int ni, int nj, int nk, int nl,
                double alpha,
                double beta,
                std::vector<std::vector<double>>& tmp,
                std::vector<std::vector<double>>& A,
                std::vector<std::vector<double>>& B,
                std::vector<std::vector<double>>& C,
                std::vector<std::vector<double>>& D)
{
    /* Use raw pointers for contiguous access inside the loops.
     * The outermost dimension of each vector is the row index. */
    const std::size_t Bstride = static_cast<std::size_t>(nj);
    const std::size_t Cstride = static_cast<std::size_t>(nl);

    /* -----------------------------------------------------------
       Phase 1 – Compute tmp = alpha * A * B
       ----------------------------------------------------------- */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < ni; ++i) {
        double* restrict tmpRow = (double*)tmp[i].data();
        const double* restrict aRow = (double*)A[i].data();
        for (int j = 0; j < nj; ++j) {
            double sum = 0.0;
            const double* restrict bCol = (double*)B[0].data() + j;
            for (int k = 0; k < nk; ++k) {
                sum += aRow[k] * (bCol[k * Bstride]);
            }
            tmpRow[j] = alpha * sum;
        }
    }

    /* -----------------------------------------------------------
       Phase 2 – Compute D = beta * D + tmp * C
       ----------------------------------------------------------- */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < ni; ++i) {
        double* restrict dRow = (double*)D[i].data();
        for (int j = 0; j < nl; ++j) {
            double val = beta * dRow[j];
            double* restrict cCol = (double*)C[0].data() + j;
            const double* restrict tmpRow = (double*)tmp[i].data();
            for (int k = 0; k < nj; ++k) {
                val += tmpRow[k] * (cCol[k * Cstride]);
            }
            dRow[j] = val;
        }
    }
}
