/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_durbin(int n,
                   std::vector<double>& r,
                   std::vector<double>& y)
{
    // Allocate temporary storage once
    std::vector<double> z(n);

    // Pointers to the underlying data for faster access
    const double* rptr = r.data();
    double* yptr      = y.data();
    double* zptr      = z.data();

    // Initialize
    yptr[0]  = -rptr[0];
    double beta = 1.0;
    double alpha = -rptr[0];

    for (int k = 1; k < n; ++k) {
        // Update beta
        beta = (1.0 - alpha * alpha) * beta;

        // Sum inner product r[k-i-1] * y[i]
        double sum = 0.0;
        // Vectorised inner product
#pragma omp simd reduction(+:sum)
        for (int i = 0; i < k; ++i) {
            sum += rptr[k - i - 1] * yptr[i];
        }

        // Compute new alpha
        alpha = -(rptr[k] + sum) / beta;

        // Update z[i] = y[i] + alpha * y[k-i-1]
#pragma omp simd
        for (int i = 0; i < k; ++i) {
            zptr[i] = yptr[i] + alpha * yptr[k - i - 1];
        }

        // Copy z back to y
#pragma omp simd
        for (int i = 0; i < k; ++i) {
            yptr[i] = zptr[i];
        }

        // Store final element
        yptr[k] = alpha;
    }
}
