/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_cholesky(int n,
                     std::vector<std::vector<double>>& A) {
    // Use OpenMP to parallelise the outer loop (rows).  Each row
    // depends only on previous rows, so the iterations are independent.
    #pragma omp parallel for schedule(static, 1)
    for (int i = 0; i < n; ++i) {
        // first j < i iterations
        for (int j = 0; j < i; ++j) {
            double sum = 0.0;
            for (int k = 0; k < j; ++k) {
                sum += A[i][k] * A[j][k];
            }
            A[i][j] = (A[i][j] - sum) / A[j][j];
        }

        // diagonal entry
        double sum = 0.0;
        for (int k = 0; k < i; ++k) {
            sum += A[i][k] * A[i][k];
        }
        A[i][i] -= sum;
        A[i][i] = std::sqrt(A[i][i]);
    }
}
