void kernel_lu(int n,
	       std::vector<std::vector<double>>& A) {
    // Local alias for faster access to rows
    std::vector<double*> rows(n);
    for (int i = 0; i < n; ++i) rows[i] = A[i].data();

    for (int i = 0; i < n; ++i) {
        double* rowI = rows[i];

        // --- Compute L part (upper triangular) ---
        for (int j = 0; j < i; ++j) {
            double* rowJ = rows[j];
            double sum = 0.0;
            // Accumulate A[i][k] * A[k][j]
            for (int k = 0; k < j; ++k) {
                sum += rowI[k] * rows[k][j];
            }
            rowI[j] = (rowI[j] - sum) / rowJ[j];
        }

        // --- Compute U part (lower triangular) ---
        for (int j = i; j < n; ++j) {
            double* rowJ = rows[j];
            double sum = 0.0;
            for (int k = 0; k < i; ++k) {
                sum += rowI[k] * rows[k][j];
            }
            rowI[j] -= sum;
        }
    }
}
