// Compute mean, center data and compute covariance matrix.
// The function preserves the exact behaviour of the original version
// but is heavily optimised for modern x86‑64 CPUs (8 threads, GCC O2 + OpenMP).
// The interface is kept unchanged.
void kernel_covariance(int m, int n,
                       std::vector<std::vector<double>>& data,
                       std::vector<std::vector<double>>& cov,
                       std::vector<double>& mean)
{
    // ----- 1) Compute mean ----------------------------------------------------
    // Parallel reduction on m elements, each accumulates over n rows.
    // Use a 2‑D for a balanced work distribution.
#pragma omp parallel for schedule(static)
    for (int col = 0; col < m; ++col) {
        double sum = 0.0;
        for (int row = 0; row < n; ++row) {
            sum += data[row][col];
        }
        mean[col] = sum / static_cast<double>(n);
    }

    // ----- 2) Center the data -------------------------------------------------
    // Each row can be processed independently. Use a cache‑friendly inner loop.
#pragma omp parallel for schedule(static)
    for (int row = 0; row < n; ++row) {
        double* row_ptr = data[row].data();
        const double* mean_ptr = mean.data();
        for (int col = 0; col < m; ++col) {
            row_ptr[col] -= mean_ptr[col];
        }
    }

    // ----- 3) Compute covariance matrix ---------------------------------------
    // We only compute the upper triangle and mirror it.
    // Each thread processes a contiguous block of rows of the resulting matrix.
#pragma omp parallel for schedule(static)
    for (int i = 0; i < m; ++i) {
        double* cov_i = cov[i].data();
        const double* col_i_ptr = data[0].data() + i; // column i pointer
        for (int j = i; j < m; ++j) {
            double sum = 0.0;
            // accumulate dot product of column i and column j
            for (int k = 0; k < n; ++k) {
                sum += data[k][i] * data[k][j];
            }
            double value = sum / (static_cast<double>(n) - 1.0);
            cov_i[j] = value;
            cov[j][i] = value;   // symmetry
        }
    }
}
