#include <cmath>
#include <vector>
#include <omp.h>

void kernel_correlation(int m, int n,
                        std::vector<std::vector<double>>& data,
                        std::vector<std::vector<double>>& corr,
                        std::vector<double>& mean,
                        std::vector<double>& stddev)
{
    const double eps = 0.1;
    const double inv_sqrt_n = 1.0 / std::sqrt(static_cast<double>(n));

    /* --- 1. compute mean for each column ------------------------------------- */
#pragma omp parallel for schedule(static)
    for (int j = 0; j < m; ++j) {
        double sum = 0.0;
        for (int i = 0; i < n; ++i) sum += data[i][j];
        mean[j] = sum / static_cast<double>(n);
    }

    /* --- 2. compute stddev for each column ---------------------------------- */
#pragma omp parallel for schedule(static)
    for (int j = 0; j < m; ++j) {
        double sum_sq = 0.0;
        const double mu = mean[j];
        for (int i = 0; i < n; ++i) {
            double d = data[i][j] - mu;
            sum_sq += d * d;
        }
        stddev[j] = std::sqrt(sum_sq / static_cast<double>(n));
        /* handle near-zero std. dev. */
        if (stddev[j] <= eps) stddev[j] = 1.0;
    }

    /* --- 3. standardize data ------------------------------------------------- */
#pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < m; ++j) {
            data[i][j] = (data[i][j] - mean[j]) * inv_sqrt_n * (1.0 / stddev[j]);
        }
    }

    /* --- 4. compute correlation matrix -------------------------------------- */
    /* first set diagonal to 1 */
#pragma omp parallel for schedule(static)
    for (int i = 0; i < m; ++i) {
        corr[i][i] = 1.0;
    }

    /* compute upper triangle and mirror */
#pragma omp parallel for schedule(dynamic)
    for (int i = 0; i < m - 1; ++i) {
        for (int j = i + 1; j < m; ++j) {
            double dot = 0.0;
            for (int k = 0; k < n; ++k) dot += data[k][i] * data[k][j];
            corr[i][j] = dot;          // because data already standardized
            corr[j][i] = dot;
        }
    }
}
