{
    /* --------------------------------------------------------------------
                         matrix multiplication A[ni×nk] * B[nk×nj] → E[ni×nj]
       -------------------------------------------------------------------- */
    #pragma omp parallel for schedule(static,1) collapse(2)
    for (int i = 0; i < ni; ++i) {
        std::vector<double> *Ei = &E[i];
        for (int j = 0; j < nj; ++j) {
            double sum = 0.0;
            for (int k = 0; k < nk; ++k) {
                sum += A[i][k] * B[k][j];
            }
            (*Ei)[j] = sum;
        }
    }

    /* --------------------------------------------------------------------
                          matrix multiplication C[nj×nm] * D[nm×nl] → F[nj×nl]
       -------------------------------------------------------------------- */
    #pragma omp parallel for schedule(static,1) collapse(2)
    for (int i = 0; i < nj; ++i) {
        std::vector<double> *Fi = &F[i];
        for (int j = 0; j < nl; ++j) {
            double sum = 0.0;
            for (int k = 0; k < nm; ++k) {
                sum += C[i][k] * D[k][j];
            }
            (*Fi)[j] = sum;
