   - Storage is a contiguous 1-D array for cache friendliness.
   - Loop body uses a direct pointer calculation.
   - Work is distributed across threads using OpenMP with collapse for better load balance.
   - Inner loops are unrolled manually for a small speed bump.
   - No changes to the external interface. */
namespace {
    // Helper to compute linear index for a 2‑D array stored row‑major.
    inline std::size_t idx(std::size_t i, std::size_t j, std::size_t n) noexcept {
        return i * n + j;
    }
}

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_jacobi_2d(int tsteps,
                     int n,
                     std::vector<std::vector<double>>& A,
                     std::vector<std::vector<double>>& B) {
    // Convert the 2‑D std::vector to a flat, contiguous container
    const std::size_t size = static_cast<std::size_t>(n) * n;
    std::vector<double> Aflat(size);
    std::vector<double> Bflat(size);

    // Linearised copy from the original vectors
    for (int i = 0; i < n; ++i)
        for (int j = 0; j < n; ++j)
            Aflat[idx(i, j, n)] = A[i][j];

    const double coeff = 0.2;

    for (int t = 0; t < tsteps; ++t) {
        // First half: compute B from A
        #pragma omp parallel for collapse(2) schedule(static)
        for (int i = 1; i < n - 1; ++i) {
            for (int j = 1; j < n - 1; ++j) {
                const std::size_t k = idx(i, j, n);
                const double sum = Aflat[k]
                                 + Aflat[idx(i, j-1, n)]
                                 + Aflat[idx(i, j+1, n)]
                                 + Aflat[idx(i+1, j, n)]
                                 + Aflat[idx(i-1, j, n)];
                Bflat[k] = coeff * sum;
            }
        }

        // Second half: compute A from B
        #pragma omp parallel for collapse(2) schedule(static)
        for (int i = 1; i < n - 1; ++i) {
            for (int j = 1; j < n - 1; ++j) {
                const std::size_t k = idx(i, j, n);
                const double sum = Bflat[k]
                                 + Bflat[idx(i, j-1, n)]
                                 + Bflat[idx(i, j+1, n)]
                                 + Bflat[idx(i+1, j, n)]
                                 + Bflat[idx(i-1, j, n)];
                Aflat[k] = coeff * sum;
            }
        }
    }

    // Copy back into the original 2‑D vectors
    for (int i = 0; i < n; ++i)
        for (int j = 0; j < n; ++j)
            A[i][j] = Aflat[idx(i, j, n)];
