        for (int k = 0; k < m; ++k) {
            double* Ak      = A[k].data();  // Actually row k of A
            double* Bk      = B[k].data();  // Actually row k of B
            double  aik     = Ai[k];
            double  bik     = Bk[i];
            const double alphaAik = s_alpha * aik;
            const double alphaBik = s_alpha * bik;

            for (int j = 0; j <= i; ++j) {
                // C[i][j] += A[j][k]*alpha*B[i][k] + B[j][k]*alpha*A[i][k];
