namespace detail
{
    inline int match(int b1, int b2) noexcept
    {
        return (b1 + b2 == 3) ? 1 : 0;
    }
}

/* Helper to linearise a 2‑D table stored as a vector of vectors.
   The table is assumed to be square and of size `n*n`. */
inline int&  tbl(std::vector<std::vector<int>>& t, int i, int j, int n)
{
    return t[i][j];
}
inline const int& tbl(const std::vector<std::vector<int>>& t, int i, int j, int n)
{
    return t[i][j];
}

/* Kernel implementation.
   The algorithm fills the table along anti‑diagonals.
   Each anti‑diagonal is independent, so it can be parallelised with OpenMP. */
void kernel_nussinov(int n, std::vector<int>& seq,
                     std::vector<std::vector<int>>& table)
{
    /* Statically size the table if it was not already. */
    if ((int)table.size() != n || (int)table[0].size() != n)
    {
        table.assign(n, std::vector<int>(n, 0));
    }

    /* Iterate over increasing distance between i and j (the anti‑diagonals). */
    #pragma omp parallel for schedule(static)
    for (int dist = 1; dist < n; ++dist)
    {
        for (int i = 0; i + dist < n; ++i)
        {
            int j = i + dist;

            /* Initialise from neighbours. */
            int best = tbl(table, i, j-1, n);
            if (i + 1 < n)
                best = std::max(best, tbl(table, i+1, j, n));

            /* Match or unmatch the pair (i,j). */
            if (i + 1 < n)
            {
                int val = tbl(table, i+1, j-1, n) + detail::match(seq[i], seq[j]);
                if (i == j-1)           // no interior positions
                    val = tbl(table, i+1, j-1, n);
                best = std::max(best, val);
            }

            /* Split optimisation over all k between i and j. */
            for (int k = i+1; k < j; ++k)
            {
                int v = tbl(table, i, k, n) + tbl(table, k+1, j, n);
                if (v > best)
                    best = v;
            }

            tbl(table, i, j, n) = best;
        }
    }
}
