/* Main computational kernel. The whole function will be timed,
   including the call and return. */
/* QR Decomposition with Modified Gram Schmidt:
   http://www.inf.ethz.ch/personal/gander/ */
void kernel_gramschmidt(int m, int n,
                        std::vector<std::vector<double>>& A,
                        std::vector<std::vector<double>>& R,
                        std::vector<std::vector<double>>& Q)
{
    /* To guarantee contiguous layout, copy to a flat buffer,
       perform all computations on it, then copy back. */
    std::vector<double> flatA(m * n);
    std::vector<double> flatQ(m * n);
    std::vector<double> flatR(n * n);

    auto idx = [&](int i, int j) -> int { return i * n + j; };

    /* copy A to flat buffer */
    for (int i = 0; i < m; ++i)
        for (int j = 0; j < n; ++j)
            flatA[idx(i, j)] = A[i][j];

    /* Main QR loop */
    for (int k = 0; k < n; ++k) {
        /* 1. Compute norm of column k of flatA */
        double nrm = 0.0;
#pragma omp parallel for reduction(+:nrm) schedule(static)
        for (int i = 0; i < m; ++i)
            nrm += flatA[idx(i, k)] * flatA[idx(i, k)];
        flatR[k * n + k] = std::sqrt(nrm);

        double inv_r = 1.0 / flatR[k * n + k];

        /* 2. Compute Q(:,k) = A(:,k) / R(k,k) */
#pragma omp parallel for schedule(static)
        for (int i = 0; i < m; ++i)
            flatQ[idx(i, k)] = flatA[idx(i, k)] * inv_r;

        /* 3. Orthogonalize remaining columns */
        for (int j = k + 1; j < n; ++j) {
            /* a) R(k,j) = Q(:,k)^T * A(:,j) */
            double rkj = 0.0;
#pragma omp parallel for reduction(+:rkj) schedule(static)
            for (int i = 0; i < m; ++i)
                rkj += flatQ[idx(i, k)] * flatA[idx(i, j)];
            flatR[k * n + j] = rkj;

            /* b) A(:,j) -= Q(:,k) * R(k,j) */
#pragma omp parallel for schedule(static)
            for (int i = 0; i < m; ++i)
                flatA[idx(i, j)] -= flatQ[idx(i, k)] * rkj;
        }
    }

    /* copy results back to the 2‑D vectors */
    for (int i = 0; i < m; ++i) {
        for (int j = 0; j < n; ++j)
            Q[i][j] = flatQ[idx(i, j)];
    }
    for (int i = 0; i < n; ++i)
        for (int j = 0; j < n; ++j)
            R[i][j] = flatR[i * n + j];
}
