/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_ludcmp(int n,
                   std::vector<std::vector<double>>& A,
                   std::vector<double>& b,
                   std::vector<double>& x,
                   std::vector<double>& y) {
    // ------------------------------------------------------------------
    // LU factorisation (L*U = A).  The algorithm is in‑place.  The
    // original code uses standard for‑loops.  We keep the semantics
    // intact while enabling SIMD vectorisation with `#pragma omp simd`
    // on the innermost loops.  The outermost loop is still serial
    // because each row depends on all previous rows.
    // ------------------------------------------------------------------
    for (int i = 0; i < n; ++i) {
        std::vector<double>& row_i = A[i];

        // --- compute lower part (i+1..n-1)
        for (int j = 0; j < i; ++j) {
            double w = row_i[j];
            const std::vector<double>& row_j = A[j];
#pragma omp simd reduction(-:w)
            for (int k = 0; k < j; ++k) {
                w -= row_i[k] * row_j[k];
            }
            row_i[j] = w / row_j[j];
        }

        // --- compute upper part (j>=i)
        for (int j = i; j < n; ++j) {
            double w = row_i[j];
#pragma omp simd reduction(-:w)
            for (int k = 0; k < i; ++k) {
                w -= row_i[k] * A[k][j];
            }
            row_i[j] = w;
        }
    }

    // ------------------------------------------------------------------
    // Forward substitution: y = L \ b
    // ------------------------------------------------------------------
    for (int i = 0; i < n; ++i) {
        double w = b[i];
        const std::vector<double>& row_i = A[i];
#pragma omp simd reduction(-:w)
        for (int j = 0; j < i; ++j) {
            w -= row_i[j] * y[j];
        }
        y[i] = w;
    }

    // ------------------------------------------------------------------
    // Backward substitution: x = U \ y
    // ------------------------------------------------------------------
    for (int i = n - 1; i >= 0; --i) {
        double w = y[i];
        const std::vector<double>& row_i = A[i];
#pragma omp simd reduction(-:w)
        for (int j = i + 1; j < n; ++j) {
            w -= row_i[j] * x[j];
        }
        x[i] = w / row_i[i];
    }
}
