    double* __restrict c = nullptr;
    double* __restrict a = nullptr;
    double* __restrict b = nullptr;

    // Allocate temporary contiguous buffers if the inner vectors
    // are not contiguous in memory (most std::vector<vector<T>> implementations
    // store each inner vector separately).  For maximum speed we copy into
    // these buffers if needed.
    bool copy_needed = false;

    for (int i = 0; i < m; ++i) {
        if (C[i].size() != n || B[i].size() != n || A[i].size() != m) {
            copy_needed = true;
            break;
        }
    }

    if (copy_needed) {
        std::vector<double> cbuf(m * n);
        std::vector<double> abuf(m * m);
        std::vector<double> bbuf(m * n);

        for (int i = 0; i < m; ++i) {
            std::copy(C[i].begin(), C[i].end(), cbuf.begin() + i * n);
            std::copy(B[i].begin(), B[i].end(), bbuf.begin() + i * n);
        }
        for (int i = 0; i < m; ++i) {
            std::copy(A[i].begin(), A[i].end(), abuf.begin() + i * m);
        }
        c = cbuf.data();
        a = abuf.data();
        b = bbuf.data();

        #pragma omp parallel for collapse(2) schedule(static)
        for (int i = 0; i < m; ++i) {
            for (int j = 0; j < n; ++j) {
                double temp2 = 0.0;
                for (int k = 0; k < i; ++k) {
                    double aik = a[i * m + k];
                    c[k * n + j] += alpha * b[i * n + j] * aik;
                    temp2 += b[k * n + j] * aik;
                }
                c[i * n + j] =
                    beta * c[i * n + j] + alpha * b[i * n + j] * a[i * m + i] + alpha * temp2;
