            /* Inner loop over columns.  Keep a fast pointer to the
               current row and use indexing for neighbouring cells. */
            for (int j = 1; j <= n - 2; ++j) {
                curr[j] = (prev[j - 1] + prev[j] + prev[j + 1] +
                           curr[j - 1] + curr[j] + curr[j + 1] +
                           next[j - 1] + next[j] + next[j + 1]) * div9;
            }
        }
