    for (int j = 0; j < m; ++j) sum_p += p[j];

    /* Main double loop.  The inner loop works on a contiguous row of
       A, so the compiler can vectorise it.  The outer loop is
       parallelised with OpenMP.  The update of s[j] no longer needs
       atomic operations because each i iteration adds the same term
       to s[j] – the order is irrelevant. */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i)
    {
        double sumA = 0.0;
        const double ri = r[i];
        const double* Ai = A[i].data();          // row pointer (contiguous)
        for (int j = 0; j < m; ++j)
        {
            double aij = Ai[j];
            s[j] += ri * aij;     // update s[j]
            sumA += aij;          // accumulate row sum for q[i]
        }
        q[i] = sumA + sum_p;      // finished q[i]
    }
}
