void kernel_heat_3d(int tsteps,
                    int n,
                    std::vector<std::vector<std::vector<double>>>& A,
                    std::vector<std::vector<std::vector<double>>>& B)
{
    constexpr double coeff  = 0.125;   // 1/8
    constexpr double coeffA = 0.25;    // 1/4

    /* Perform tsteps iterations */
    for (int t = 1; t <= tsteps; ++t)
    {
        /* Update B from A */
        #pragma omp parallel for collapse(3) schedule(static)
        for (int i = 1; i < n - 1; ++i)
        {
            for (int j = 1; j < n - 1; ++j)
            {
                for (int k = 1; k < n - 1; ++k)
                {
                    double a = A[i][j][k];
                    double sum = A[i+1][j][k] + A[i-1][j][k]
                               + A[i][j+1][k] + A[i][j-1][k]
                               + A[i][j][k+1] + A[i][j][k-1];
                    B[i][j][k] = coeffA * a + coeff * sum;
                }
            }
        }

        /* Update A from B (swap roles) */
        #pragma omp parallel for collapse(3) schedule(static)
        for (int i = 1; i < n - 1; ++i)
        {
            for (int j = 1; j < n - 1; ++j)
            {
                for (int k = 1; k < n - 1; ++k)
                {
                    double b = B[i][j][k];
                    double sum = B[i+1][j][k] + B[i-1][j][k]
                               + B[i][j+1][k] + B[i][j-1][k]
                               + B[i][j][k+1] + B[i][j][k-1];
                    A[i][j][k] = coeffA * b + coeff * sum;
