#include <vector>
#include <cstddef>
#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
/* Based on a Fortran code fragment from Figure 5 of
 * "Automatic Data and Computation Decomposition on Distributed Memory Parallel Computers"
 * by Peizong Lee and Zvi Meir Kedem, TOPLAS, 2002
 */
void kernel_adi(int tsteps, int n,
                std::vector<std::vector<double>>& u,
                std::vector<std::vector<double>>& v,
                std::vector<std::vector<double>>& p,
                std::vector<std::vector<double>>& q)
{
    const double DX{1.0 / static_cast<double>(n)};
    const double DY{1.0 / static_cast<double>(n)};
    const double DT{1.0 / static_cast<double>(tsteps)};

    const double mul1 = 2.0 * DT / (DX * DX);
    const double mul2 = 1.0 * DT / (DY * DY);

    const double a    = -mul1 / 2.0;
    const double b    = 1.0 + mul1;
    const double c    = a;
    const double d    = -mul2 / 2.0;
    const double e    = 1.0 + mul2;
    const double f    = d;

    // pre‑allocate temporary per‑row buffers once to avoid repeated
    // allocations inside the time loop
    std::vector<double> rowP(n), rowQ(n);

#pragma omp parallel
    {
        // local copies of row pointers to reduce index calculations
        std::vector<double*> ui(n), vi(n), pi(n), qi(n);

        for (int k = 0; k < n; ++k) {
            ui[k] = u[k].data();
            vi[k] = v[k].data();
            pi[k] = p[k].data();
            qi[k] = q[k].data();
        }

        for (int t = 1; t <= tsteps; ++t) {
            // ---------- sweep over i for v ----------
#pragma omp for schedule(static) nowait
            for (int i = 1; i < n - 1; ++i) {
                // forward sweep on j
                vi[0][i] = 1.0;
                pi[i][0] = 0.0;
                qi[i][0] = vi[0][i];

                for (int j = 1; j < n - 1; ++j) {
                    double denom = a * pi[i][j - 1] + b;
                    pi[i][j]      = -c / denom;
                    qi[i][j]      = (-d * ui[j][i - 1] + (1.0 + 2.0 * d) * ui[j][i]
                                    - f * ui[j][i + 1] - a * qi[i][j - 1]) / denom;
                }

                vi[n - 1][i] = 1.0;

                for (int j = n - 2; j >= 1; --j) {
                    vi[j][i] = pi[i][j] * vi[j + 1][i] + qi[i][j];
                }
            }

            // ---------- sweep over i for u ----------
#pragma omp for schedule(static)
            for (int i = 1; i < n - 1; ++i) {
                ui[i][0] = 1.0;
                pi[i][0] = 0.0;
                qi[i][0] = ui[i][0];

                for (int j = 1; j < n - 1; ++j) {
                    double denom = d * pi[i][j - 1] + e;
                    pi[i][j]      = -f / denom;
                    qi[i][j]      = (-a * vi[i - 1][j] + (1.0 + 2.0 * a) * vi[i][j]
                                    - c * vi[i + 1][j] - d * qi[i][j - 1]) / denom;
                }

                ui[i][n - 1] = 1.0;

                for (int j = n - 2; j >= 1; --j) {
                    ui[i][j] = pi[i][j] * ui[i][j + 1] + qi[i][j];
                }
            }
        }
    }   // end parallel region
}
