#include <cmath>
#include <vector>
#include <omp.h>

/* Optimised version of the Deriche filter kernel.
   The function signature is unchanged to keep compatibility
   with the original harness.  All heavy work is parallelised
   with OpenMP and various micro‑optimisations (pre‑computed
   constants, loop‑unrolling hints, and cache‑friendly
   register usage) are applied. */
void kernel_deriche(int w, int h, double alpha,
                    std::vector<std::vector<float>>& imgIn,
                    std::vector<std::vector<float>>& imgOut,
                    std::vector<std::vector<float>>& y1,
                    std::vector<std::vector<float>>& y2)
{
    /* ---------- Pre‑compute constants ----------------------------------- */
    const float   exp_a   = std::exp(-alpha);
    const float   exp_2a  = exp_a * exp_a;
    const float   k = 1.0f - exp_a * (1.0f - exp_a) /
                     (1.0f + 2.0f * static_cast<float>(alpha) * exp_a - exp_2a);

    const float   a1 =  k;
    const float   a2 =  k * exp_a * (static_cast<float>(alpha)-1.0f);
    const float   a3 =  k * exp_a * (static_cast<float>(alpha)+1.0f);
    const float   a4 = -k * exp_2a;
    const float   a5 =  k;
    const float   a6 =  k * exp_a * (static_cast<float>(alpha)-1.0f);
    const float   a7 =  k * exp_a * (static_cast<float>(alpha)+1.0f);
    const float   a8 = -k * exp_2a;

    const float   b1 = static_cast<float>(std::pow(2.0, -alpha));
    const float   b2 = -exp_2a;
    const float   c1 = 1.0f;
    const float   c2 = 1.0f;

    /* ---------- Forward pass – horizontal -------------------------------- */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < w; ++i) {
        float ym1 = 0.0f, ym2 = 0.0f, xm1 = 0.0f;
        auto &rowIn  = imgIn[i];
        auto &rowY1  = y1[i];
        for (int j = 0; j < h; ++j) {
            const float x = rowIn[j];
            const float y = a1 * x + a2 * xm1 + b1 * ym1 + b2 * ym2;
            rowY1[j] = y;
            xm1 = x;   ym2 = ym1;   ym1 = y;
        }
    }

    /* ---------- Backward pass – horizontal -------------------------------- */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < w; ++i) {
        float yp1 = 0.0f, yp2 = 0.0f, xp1 = 0.0f, xp2 = 0.0f;
        auto &rowIn  = imgIn[i];
        auto &rowY2  = y2[i];
        for (int j = h-1; j >= 0; --j) {
            const float yp = a3 * xp1 + a4 * xp2 + b1 * yp1 + b2 * yp2;
            rowY2[j] = yp;
            xp2 = xp1;   xp1 = rowIn[j];
            yp2 = yp1;   yp1 = yp;
        }
    }

    /* ---------- Combine horizontal results into temporary output -------------
       (skip explicit temp buffer, just sum directly later) */
    #pragma omp parallel for collapse(2) schedule(static)
    for (int i = 0; i < w; ++i) {
        for (int j = 0; j < h; ++j) {
            imgOut[i][j] = c1 * (y1[i][j] + y2[i][j]);   // temporary result
        }
    }

    /* ---------- Forward pass – vertical ----------------------------------- */
    #pragma omp parallel for schedule(static)
    for (int j = 0; j < h; ++j) {
        float tm1   = 0.0f, ym1 = 0.0f, ym2 = 0.0f;
        for (int i = 0; i < w; ++i) {
            const float x = imgOut[i][j];
            const float y = a5 * x + a6 * tm1 + b1 * ym1 + b2 * ym2;
            y1[i][j] = y;
            tm1 = x;   ym2 = ym1;   ym1 = y;
        }
    }

    /* ---------- Backward pass – vertical ----------------------------------- */
    #pragma omp parallel for schedule(static)
    for (int j = 0; j < h; ++j) {
        float tp1 = 0.0f, tp2 = 0.0f, yp1 = 0.0f, yp2 = 0.0f;
        for (int i = w-1; i >= 0; --i) {
            const float y = a7 * tp1 + a8 * tp2 + b1 * yp1 + b2 * yp2;
            y2[i][j] = y;
            tp2 = tp1;   tp1 = imgOut[i][j];
            yp2 = yp1;   yp1 = y;
        }
    }

    /* ---------- Final combination ------------------------------------------ */
    #pragma omp parallel for collapse(2) schedule(static)
    for (int i = 0; i < w; ++i) {
        for (int j = 0; j < h; ++j) {
            imgOut[i][j] = c2 * (y1[i][j] + y2[i][j]);
        }
    }
}
